import React from "react";
import styled, { createGlobalStyle } from "styled-components";

import IntroPanel from "./intro";
import WorkPanel from "./work";
import ProjectsPanel from "./projects";
import AboutPanel from "./about";
import Footer from "./footer";

import ColorButton from "./color_button";
import ResumeButton from "./resume_button";

// TODO: Make color appear via scroll
// TODO: ^^ or make child components color their respective panels (i.e. if they hover over title but not the panel)

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      backgroundColor: "#b5feff",
      panelColor: "#ffffff",
      buttonColor: "#51b5b5",
      headingColor: "#2f7fc4",
      bodyColor: "#1c1c1c",
      highlightColor: "#ffb429",
    };
  }

  randomColorScheme = (e) => {
    e.preventDefault();
  };

  render() {
    return (
      <Main backgroundColor={this.state.backgroundColor}>
        <GlobalStyle />
        <ColorButton />
        <IntroPanel
          panelColor={this.state.panelColor}
          buttonColor={this.state.buttonColor}
        />
        <AboutPanel panelColor={this.state.panelColor} />
        <WorkPanel panelColor={this.state.panelColor} />
        <ProjectsPanel panelColor={this.state.panelColor} />
        <Footer />
      </Main>
    );
  }
}

export default App;

const Main = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  height: 100%;
  width: 100%;
  background: ${(props) => props.backgroundColor};
  transition: all 0.8s ease-in;
  * {
    transition: all 0.8s ease-in;
  }
`;

const GlobalStyle = createGlobalStyle`body {
  background: ${(props) => (props.isColor && "red") || "#000000"}
}`;
