import React, { useState } from "react";
import styled from "styled-components";

// const Panel = (props) => {
//   return <StyledPanel isColor={props.isColor}>{props.children}</StyledPanel>;
// };

class Panel extends React.Component {
  constructor(props) {
    super(props);
    this.state = { isColor: props.isColor };
  }

  render() {
    return (
      <StyledPanel color={this.props.color}>{this.props.children}</StyledPanel>
    );
  }
}

export default Panel;

const StyledPanel = styled.div`
  user-select: none;
  cursor: default;
  margin: 3.5rem 1rem 3rem 1rem;
  padding: 3rem 1rem 1rem 1rem;
  background: ${(props) => (props.isColor && "green") || "#1c1c1c"};
  display: flex;
  flex-direction: column;
  width: 90%;
  min-height: 75vh;
  border-radius: 50px;
`;
